private static string GetUniqueTrashItemPath(string trashBasePath, string originalName, string timestamp)
{
    var candidate = Path.Combine(trashBasePath, $"{timestamp}_{originalName}");
    if (!File.Exists(candidate) && !Directory.Exists(candidate))
    {
        return candidate;
    }

    for (var i = 1; ; i++)
    {
        candidate = Path.Combine(trashBasePath, $"{timestamp}_{originalName}_{i}");
        if (!File.Exists(candidate) && !Directory.Exists(candidate))
        {
            return candidate;
        }
    }
}
